/// <reference lib="webworker" />

// Custom service worker for Adhan background audio
// This extends the Workbox SW generated by vite-plugin-pwa

declare const self: ServiceWorkerGlobalScope;

const ADHAN_CACHE = "adhan-audio-v1";
const ADHAN_FILES = [
  "/audio/adhan-mishary.mp3",
  "/audio/adhan-nafees.mp3",
  "/audio/adhan-dubai.mp3",
];

// Pre-cache adhan audio files on install
self.addEventListener("install", (event) => {
  event.waitUntil(
    caches.open(ADHAN_CACHE).then((cache) => cache.addAll(ADHAN_FILES))
  );
  self.skipWaiting();
});

self.addEventListener("activate", (event) => {
  event.waitUntil(self.clients.claim());
});

// Listen for messages from the main app
self.addEventListener("message", (event) => {
  const { type, data } = event.data || {};

  if (type === "SCHEDULE_ADHAN") {
    // Store adhan settings for background scheduling
    scheduleBackgroundAdhan(data);
  }

  if (type === "PLAY_ADHAN_NOTIFICATION") {
    showAdhanNotificationWithSound(data);
  }

  if (type === "SKIP_WAITING") {
    self.skipWaiting();
  }
});

// Periodic sync for background adhan (if supported)
self.addEventListener("periodicsync" as any, (event: any) => {
  if (event.tag === "adhan-check") {
    event.waitUntil(checkAndPlayAdhan());
  }
});

// Handle notification clicks
self.addEventListener("notificationclick", (event) => {
  event.notification.close();
  event.waitUntil(
    self.clients.matchAll({ type: "window", includeUncontrolled: true }).then((clients) => {
      if (clients.length > 0) {
        return clients[0].focus();
      }
      return self.clients.openWindow("/prayer");
    })
  );
});

async function showAdhanNotificationWithSound(data: {
  prayerName: string;
  adhanFile: string;
}) {
  const { prayerName, adhanFile } = data;

  // Show notification with vibration pattern
  await self.registration.showNotification(
    `🕌 ${prayerName} - Time to Pray`,
    {
      body: `It's time for ${prayerName}. May Allah accept your prayers. 🤲`,
      icon: "/favicon.ico",
      badge: "/favicon.ico",
      tag: "adhan-" + prayerName,
      requireInteraction: true,
      silent: false,
      vibrate: [200, 100, 200, 100, 200, 100, 400],
      data: { prayerName, adhanFile },
      actions: [
        { action: "open", title: "Open App" },
        { action: "dismiss", title: "Dismiss" },
      ],
    }
  );

  // Notify all open clients to play audio
  const clients = await self.clients.matchAll({ type: "window", includeUncontrolled: true });
  for (const client of clients) {
    client.postMessage({
      type: "PLAY_ADHAN_AUDIO",
      data: { prayerName, adhanFile },
    });
  }
}

// Background adhan check
async function checkAndPlayAdhan() {
  try {
    // Read settings from IndexedDB or cache
    const cache = await caches.open("adhan-settings");
    const response = await cache.match("/adhan-settings.json");
    if (!response) return;

    const settings = await response.json();
    if (!settings.enabled) return;

    const now = new Date();
    const currentTime = `${String(now.getHours()).padStart(2, "0")}:${String(now.getMinutes()).padStart(2, "0")}`;

    const prayerSchedule: Record<string, string> = {
      Fajr: "05:23",
      Sunrise: "06:45",
      Dhuhr: "12:30",
      Asr: "15:45",
      Maghrib: "18:12",
      Isha: "19:42",
    };

    for (const [name, time] of Object.entries(prayerSchedule)) {
      if (time === currentTime && settings.prayers[name]) {
        const option = settings.adhanOptions?.find(
          (o: any) => o.id === settings.selectedAdhan
        );
        await showAdhanNotificationWithSound({
          prayerName: name,
          adhanFile: option?.file || "/audio/adhan-mishary.mp3",
        });
        break;
      }
    }
  } catch (err) {
    console.error("Background adhan check failed:", err);
  }
}

function scheduleBackgroundAdhan(settings: any) {
  // Store settings in cache for background access
  caches.open("adhan-settings").then((cache) => {
    cache.put(
      "/adhan-settings.json",
      new Response(JSON.stringify(settings), {
        headers: { "Content-Type": "application/json" },
      })
    );
  });
}
